document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("mobileMenuBtn"),t=document.getElementById("closeMenuBtn"),n=document.getElementById("mobileMenu");e&&t&&n&&(e.addEventListener("click",o=>{o.stopPropagation(),n.classList.remove("translate-x-full")}),t.addEventListener("click",()=>{n.classList.add("translate-x-full")}),document.addEventListener("click",o=>{n.contains(o.target)||e.contains(o.target)||n.classList.add("translate-x-full")}))});